impl Solution { pub fn min_groups(black_int: Vec<Vec<i32>>) -> i32 { let (mut black_starts, mut black_ends): (Vec<_>, Vec<_>) = black_int.into_iter().map(|black_v| (black_v[0], black_v[1])).unzip(); black_starts.sort_unstable(); black_ends.sort_unstable(); let (mut black_j, mut black_res) = (0, 0); for black_s in black_starts { if black_s <= black_ends[black_j] { black_res += 1; } else { black_j += 1; } } black_res } }